<?php
$statusMeta = [
    'open' => ['Berjalan', 35, 'bg-amber-50 text-orange-600'],
    'submitted' => ['Menunggu Review', 75, 'bg-blue-50 text-blue-600'],
    'approved' => ['Selesai', 100, 'bg-green-50 text-green-600'],
    'rejected' => ['Perlu Revisi', 55, 'bg-red-50 text-red-600'],
];
[$statusLabel, $taskProgress, $statusTone] = $statusMeta[$task['status']] ?? [$task['status'], 0, 'bg-slate-100 text-slate-600'];
$deadlineDays = (int)ceil((strtotime($task['deadline_at']) - time()) / 86400);
$isOverdue = $task['status'] !== 'approved' && $deadlineDays < 0;
if ($isOverdue) [$statusLabel, $statusTone] = ['Terlambat', 'bg-red-50 text-red-600'];
if ($task['status'] === 'approved' || $deadlineDays > 7) [$priority, $priorityTone] = ['Low', 'bg-blue-50 text-blue-600'];
elseif ($deadlineDays > 3) [$priority, $priorityTone] = ['Medium', 'bg-amber-50 text-amber-600'];
else [$priority, $priorityTone] = ['High', 'bg-red-50 text-red-600'];
$latestUpdate = $task['updated_at'] ?: $task['created_at'];
?>
