<script>(()=>{const bind=(open,modal,close)=>{const panel=document.querySelector(modal);document.querySelectorAll(open).forEach(b=>b.addEventListener('click',()=>{panel?.classList.remove('hidden');panel?.classList.add('flex')}));document.querySelectorAll(close).forEach(b=>b.addEventListener('click',()=>{panel?.classList.add('hidden');panel?.classList.remove('flex')}));panel?.addEventListener('click',e=>{if(e.target===panel){panel.classList.add('hidden');panel.classList.remove('flex')}})};bind('.open-submit-modal','.submit-task-modal','.close-submit-modal');bind('.open-review-modal','.review-task-modal','.close-review-modal');bind('.open-edit-task','.edit-task-modal','.close-edit-task');bind('.open-reopen-modal','.reopen-task-modal','.close-reopen-modal');document.querySelectorAll('.focus-comment').forEach(b=>b.addEventListener('click',()=>document.getElementById('taskCommentInput')?.focus()));requestAnimationFrame(()=>document.querySelectorAll('.task-detail-progress').forEach(b=>b.classList.add('is-ready')))})();</script>
